(function(){
  "use strict";const OA=window.OrbArena,clean=(value)=>OA.AbilityVisualRegistry.className(value);
  const originalRender=OA.CharacterSelectUI.prototype.render,originalPreview=OA.CharacterSelectUI.prototype.renderPreview;
  OA.CharacterSelectUI.prototype.decorateOrbs=function(){this.grid.querySelectorAll(".character-card[data-character]").forEach((card)=>{const character=OA.CharacterRegistry.get(card.dataset.character),orb=card.querySelector(".card-orb");if(!character||!orb)return;card.classList.add(`rarity-${clean(character.rarity)}`,`material-${clean(character.texture)}`);card.style.setProperty("--secondary",character.secondary);orb.setAttribute("aria-label",`Retrato de ${character.name}`);orb.insertAdjacentHTML("afterbegin",`<i class="orb-aura"></i><i class="orb-shell"></i><i class="orb-material"></i><i class="orb-rune"></i>`);const small=card.querySelector("small");small.innerHTML=`<span class="rarity-badge rarity-${clean(character.rarity)}">${character.rarity}</span> <span>${character.class}</span>`;});};
  OA.CharacterSelectUI.prototype.render=function(){originalRender.call(this);this.decorateOrbs();};
  OA.CharacterSelectUI.prototype.renderPreview=function(){originalPreview.call(this);const character=this.selected,orb=this.preview.querySelector(".hero-orb");if(orb){orb.classList.add(`material-${clean(character.texture)}`);orb.style.setProperty("--secondary",character.secondary);orb.insertAdjacentHTML("afterbegin",`<i class="orb-aura"></i><i class="orb-shell"></i><i class="orb-material"></i><i class="orb-rune"></i><i class="orb-satellite"></i>`);}const tabs=this.preview.querySelector(".detail-tabs");tabs?.insertAdjacentHTML("beforebegin",`<div class="character-identity-row"><span class="rarity-badge rarity-${clean(character.rarity)}">${character.rarity}</span><span class="element-badge" style="--badge:${character.color}">${character.element}</span><span class="ds-badge">Dificuldade ${character.difficulty}</span></div>`);const custom=this.preview.querySelector('[data-detail-pane="custom"]');custom?.insertAdjacentHTML("beforeend",`<div class="skin-strip"><button style="--skin:${character.color}" aria-label="Skin original selecionada">ORIGINAL</button><button style="--skin:${character.secondary}" aria-label="Preview de skin alternativa">ALTERNATIVA</button><button style="--skin:${character.glow}" aria-label="Preview de skin energética">ENERGIA</button></div><blockquote><b>LORE</b> ${character.title}. ${character.description}</blockquote>`);};
}());
